function subsets(nums) {
  const result = [];
  function backtrack(start, current) {
    result.push([...current]);
    for (let i = start; i < nums.length; i++) {
      current.push(nums[i]);      // choose
      backtrack(i + 1, current);   // explore
      current.pop();               // unchoose
    }
  }
  backtrack(0, []);
  return result;
}

