// Recursive sum
function sumRec(n) {
  if (n <= 0) return 0;
  return n + sumRec(n - 1);
}

// Iterative equivalent
function sumIter(n) {
  let total = 0;
  for (let i = 1; i <= n; i++) {
    total += i;
  }
  return total;
}

